**Important:** The existing `posts.test.ts` and `comments.test.ts` only test GET endpoints and never examine user passwords, so hashing seed passwords has zero impact on those tests.

---

### Step 4: Modify `src/routes/posts.ts` -- Add auth and ownership checks

**New imports to add:**
```ts
import { authenticate, AuthRequest } from "../middleware/auth.js";
```

**Changes to routes:**

- **`GET /`** and **`GET /:id`**: NO changes. These remain public.

- **`POST /`**: Add `authenticate` as middleware. Change the handler to use `AuthRequest` type. Replace `userId: userId || 1` with `userId: (req as AuthRequest).userId!` so the userId always comes from the token.
  ```ts
  router.post("/", authenticate, (req: AuthRequest, res) => {
    const { title, content } = req.body;
    if (!title || !content) {
      res.status(400).json({ error: "title and content are required" });
      return;
    }
    const newPost: Post = {
      id: nextId(posts),
      title,
      content,
      userId: req.userId!,
      createdAt: new Date().toISOString(),
    };
    posts.push(newPost);
    res.status(201).json(newPost);
  });
  ```

- **`PUT /:id`**: Add `authenticate` as middleware. Add ownership check: after finding the post, compare `posts[index].userId !== req.userId` -- if mismatch, return `403` with `{ error: "Forbidden" }`.
  ```ts
  router.put("/:id", authenticate, (req: AuthRequest, res) => {
    const id = parseInt(req.params.id, 10);
    const index = posts.findIndex((p) => p.id === id);
    if (index === -1) {
      res.status(404).json({ error: "Post not found" });
      return;
    }
    if (posts[index].userId !== req.userId) {
      res.status(403).json({ error: "Forbidden" });
      return;
    }
    const { title, content } = req.body;
    if (title) posts[index].title = title;
    if (content) posts[index].content = content;
    res.json(posts[index]);
  });
  ```

- **`DELETE /:id`**: Same pattern as PUT -- add `authenticate`, add ownership check returning 403 if not owner.
  ```ts
  router.delete("/:id", authenticate, (req: AuthRequest, res) => {
    const id = parseInt(req.params.id, 10);
    const index = posts.findIndex((p) => p.id === id);
    if (index === -1) {
      res.status(404).json({ error: "Post not found" });
      return;
    }
    if (posts[index].userId !== req.userId) {
      res.status(403).json({ error: "Forbidden" });
      return;
    }
    const deleted = posts.splice(index, 1);
    res.json(deleted[0]);
  });
  ```

